#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin>>n;
    for(int i=0;i<n;i++){
        int m;
        cin>>m;
        string a[m];
        for(int j=0;j<m;j++){
            cin>>a[j];
        }
        sort(a,a+m);
        string t="";
        for(int j=0;j<m;j++){
            t+=a[j];
        }
        int p=1;
        for(int j=1;j<t.length();j++){
            if(t[j]<t[j-1]){
                p=0;
                break;
            }
        }
        cout<<p<<endl;
    }
    return 0;
}
